if (! function_exists('array_stack')) {
    function array_stack($key, $operation, $items = null)
    {
        $notesDir = __DIR__ . '/../../workspace/notes';
        if (!is_dir($notesDir)) { mkdir($notesDir, 0755, true); }
        $filePath = $notesDir . '/' . md5('stack_' . $key) . '.stack.json';

        $stack = [];
        if (file_exists($filePath)) {
            $data = json_decode(file_get_contents($filePath), true);
            if (is_array($data)) { $stack = $data; }
        }

        switch ($operation) {
            case 'push':
                if (empty($items)) {
                    return json_encode(['error' => 'Must provide items to push']);
                }
                foreach ($items as $item) {
                    array_push($stack, (string)$item);
                }
                file_put_contents($filePath, json_encode($stack));
                return json_encode(['operation' => 'push', 'stack_size' => count($stack), 'top' => end($stack)]);
            
            case 'pop':
                if (empty($stack)) {
                    return json_encode(['error' => 'Stack is empty', 'stack_size' => 0]);
                }
                $popped = array_pop($stack);
                file_put_contents($filePath, json_encode($stack));
                return json_encode(['operation' => 'pop', 'popped' => $popped, 'stack_size' => count($stack)]);
            
            case 'peek':
                if (empty($stack)) {
                    return json_encode(['error' => 'Stack is empty', 'stack_size' => 0]);
                }
                return json_encode(['operation' => 'peek', 'top' => end($stack), 'stack_size' => count($stack)]);
            
            case 'size':
                return json_encode(['operation' => 'size', 'stack_size' => count($stack)]);
            
            case 'clear':
                file_put_contents($filePath, json_encode([]));
                return json_encode(['operation' => 'clear', 'stack_size' => 0]);
            
            case 'all':
                return json_encode(['operation' => 'all', 'stack' => $stack, 'stack_size' => count($stack)]);
            
            default:
                return json_encode(['error' => "Unknown operation: $operation"]);
        }
    }
